mapper.select:
SELECT
    a.id id,
    a.site_code siteCode,
    a.review_order_no reviewOrderNo,
    a.agent_id agentId,
    a.agent_account agentAccount,
    a.level level,
    a.apply_info applyInfo,
    a.apply_time applyTime,
    a.applicant applicant,
    a.one_review_finish_time oneReviewFinishTime,
    a.reviewer reviewer,
    a.review_operation reviewOperation,
    IF(a.locker = #{adminName}, -1, 5) reviewOperation1,
    a.review_status reviewStatus,
    a.lock_status lockStatus,
    a.locker locker
FROM agent_review a


        AND a.site_code = #{vo.siteCode}


        AND a.apply_time  >=  #{vo.applyTimeStart}


        AND a.apply_time  <=  #{vo.applyTimeEnd}


        AND a.one_review_finish_time  >=  #{vo.oneReviewFinishTimeStart}


        AND a.one_review_finish_time  <=  #{vo.oneReviewFinishTimeEnd}


        AND a.review_status IN

            #{value}



        AND a.lock_status = #{vo.lockStatus}


        AND a.review_operation = #{vo.reviewOperation}


        AND a.applicant = #{vo.applicant}


        AND a.reviewer = #{vo.reviewer}


        AND a.agent_account = #{vo.agentAccount}


        AND a.review_order_no = #{vo.reviewOrderNo}





        ORDER BY applyTime asc


        ORDER BY applyTime desc



        ORDER BY oneReviewFinishTime asc


        ORDER BY oneReviewFinishTime desc



        ORDER BY reviewOperation1 ASC, a.review_operation ASC, a.review_status ASC, a.apply_time ASC
